     1→//! High-level statistical modeling API for Rust
     2→//!
     3→//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
     4→//! and `Glm` (Generalized Linear Models), integrating lower-level crates
     5→//! to provide a complete modeling workflow.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use faer::{prelude::*, Mat};
    11→use family::Family;
    12→use link::LinkFn;
    13→use ndarray::{Array1, ArrayView1, ArrayView2};
    14→use optimcore::{irls, IrlsConfig};
    15→
    16→/// Statistical modeling errors
    17→#[derive(thiserror::Error, Debug)]
    18→pub enum ModelError {
    19→    /// Linear algebra computation error
    20→    #[error("Linear algebra error: {0}")]
    21→    LinearAlgebra(String),
    22→    /// Invalid model specification
    23→    #[error("Invalid model: {0}")]
    24→    InvalidModel(String),
    25→}
    26→
    27→// Re-export important types for convenience
    28→pub use family::{Binomial, Gaussian, Poisson};
    29→pub use link::{Identity, Log, Logit};
    30→
    31→/// Common trait for all fitted models
    32→pub trait Fit {
    33→    /// Get model coefficients
    34→    fn coefficients(&self) -> &[f64];
    35→
    36→    /// Get fitted values
    37→    fn fitted(&self) -> &[f64];
    38→
    39→    /// Get residuals
    40→    fn residuals(&self) -> &[f64];
    41→
    42→    /// Get model summary
    43→    fn summary(&self) -> ModelSummary;
    44→}
    45→
    46→/// Model summary information
    47→#[derive(Debug)]
    48→pub struct ModelSummary {
    49→    /// Coefficient table
    50→    pub coefficients: Vec<CoefficientRow>,
    51→    /// R-squared (coefficient of determination)
    52→    pub r_squared: f64,
    53→    /// Adjusted R-squared
    54→    pub adj_r_squared: f64,
    55→    /// Residual standard error
    56→    pub residual_std_error: f64,
    57→    /// F-statistic for overall model significance
    58→    pub f_statistic: f64,
    59→    /// p-value for F-statistic
    60→    pub f_p_value: f64,
    61→    /// Degrees of freedom for model (number of predictors excluding intercept)
    62→    pub df_model: usize,
    63→    /// Degrees of freedom for residuals
    64→    pub df_residual: usize,
    65→}
    66→
    67→/// A row in the coefficient table
    68→#[derive(Debug)]
    69→pub struct CoefficientRow {
    70→    /// Variable name
    71→    pub name: String,
    72→    /// Estimated coefficient
    73→    pub estimate: f64,
    74→    /// Standard error
    75→    pub std_error: f64,
    76→    /// t-statistic
    77→    pub t_value: f64,
    78→    /// p-value
    79→    pub p_value: f64,
    80→}
    81→
    82→/// Linear model fitting
    83→pub struct Lm;
    84→
    85→/// Generalized linear model fitting
    86→pub struct Glm;
    87→
    88→/// Fitted linear model results
    89→#[derive(Debug)]
    90→pub struct LmFit {
    91→    coefficients: Vec<f64>,
    92→    fitted_values: Vec<f64>,
    93→    residuals: Vec<f64>,
    94→    /// Number of observations
    95→    n_obs: usize,
    96→    /// Matrix rank (for rank-deficient matrices)
    97→    rank: usize,
    98→    /// Design matrix for statistical inference (stored for covariance calculation)
    99→    x_matrix: Mat<f64>,
   100→}
   101→
   102→/// Fitted generalized linear model results
   103→#[derive(Debug)]
   104→pub struct GlmFit {
   105→    coefficients: Vec<f64>,
   106→    fitted_values: Vec<f64>,
   107→    residuals: Vec<f64>,
   108→    /// Linear predictor values (X * β)
   109→    linear_predictor: Vec<f64>,
   110→    /// Number of observations
   111→    n_obs: usize,
   112→    /// Design matrix for statistical inference
   113→    x_matrix: Mat<f64>,
   114→    /// Final deviance
   115→    deviance: f64,
   116→    /// Working weights from final IRLS iteration
   117→    weights: Vec<f64>,
   118→    /// Number of IRLS iterations
   119→    iterations: usize,
   120→    /// Whether IRLS converged
   121→    converged: bool,
   122→}
   123→
   124→impl Lm {
   125→    /// Fit a linear model using ndarray views (recommended modern API)
   126→    ///
   127→    /// This implementation uses faer's column-pivoted QR decomposition to handle
   128→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
   129→    ///
   130→    /// # Arguments
   131→    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
   132→    /// * `y` - Response vector as ndarray view (n_observations)
   133→    ///
   134→    /// # Example
   135→    /// ```
   136→    /// use ndarray::Array2;
   137→    /// use stats_models::Lm;
   138→    ///
   139→    /// // Create design matrix with intercept
   140→    /// let x = Array2::from_shape_vec((3, 2), vec![1.0, 1.0, 1.0, 2.0, 1.0, 3.0]).unwrap();
   141→    /// let y = vec![3.0, 5.0, 7.0];
   142→    ///
   143→    /// let fit = Lm::fit_ndarray(x.view(), ndarray::Array1::from(y).view()).unwrap();
   144→    /// ```
   145→    pub fn fit_ndarray(x: ArrayView2<f64>, y: ArrayView1<f64>) -> Result<LmFit, ModelError> {
   146→        let (n_rows, n_cols) = x.dim();
   147→
   148→        if y.len() != n_rows {
   149→            return Err(ModelError::InvalidModel(
   150→                "Response vector length doesn't match number of observations".to_string(),
   151→            ));
   152→        }
   153→
   154→        // Convert to faer matrices
   155→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);
   156→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y[i]);
   157→
   158→        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
   159→    }
   160→
   161→    /// Fit a linear model using raw slices (legacy API for backward compatibility)
   162→    ///
   163→    /// This implementation uses faer's column-pivoted QR decomposition to handle
   164→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
   165→    ///
   166→    /// **Note**: Consider using `fit_ndarray` for better type safety and ergonomics.
   167→    pub fn fit(
   168→        x_data: &[f64],
   169→        y_data: &[f64],
   170→        n_rows: usize,
   171→        n_cols: usize,
   172→    ) -> Result<LmFit, ModelError> {
   173→        if x_data.len() != n_rows * n_cols {
   174→            return Err(ModelError::InvalidModel(
   175→                "Design matrix dimensions don't match data".to_string(),
   176→            ));
   177→        }
   178→
   179→        if y_data.len() != n_rows {
   180→            return Err(ModelError::InvalidModel(
   181→                "Response vector length doesn't match number of observations".to_string(),
   182→            ));
   183→        }
   184→
   185→        // Create faer matrices from input data
   186→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
   187→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);
   188→
   189→        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
   190→    }
   191→
   192→    /// Internal fitting logic shared by both APIs
   193→    fn fit_internal(
   194→        x_mat: Mat<f64>,
   195→        y_mat: Mat<f64>,
   196→        n_rows: usize,
   197→        n_cols: usize,
   198→    ) -> Result<LmFit, ModelError> {
   199→        // Use column-pivoted QR for numerical stability with rank-deficient matrices
   200→        let qr = x_mat.col_piv_qr();
   201→
   202→        // Calculate rank from R matrix diagonal elements
   203→        let r_matrix = qr.R();
   204→        let tolerance = 1e-12;
   205→        let mut rank = 0;
   206→        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
   207→            if r_matrix[(i, i)].abs() > tolerance {
   208→                rank += 1;
   209→            }
   210→        }
   211→
   212→        // Handle rank-deficient matrices by checking for numerical instability
   213→        let coefficients_mat = qr.solve_lstsq(&y_mat);
   214→
   215→        // Check for numerical instability and apply correction if needed
   216→        let has_instability =
   217→            (0..coefficients_mat.nrows()).any(|i| coefficients_mat[(i, 0)].abs() > 1e10);
   218→
   219→        let final_coefficients_mat = if has_instability {
   220→            // For rank-deficient case, set coefficients for columns beyond rank to zero
   221→            let mut corrected_coefs = Vec::new();
   222→            for i in 0..coefficients_mat.nrows() {
   223→                let coef = coefficients_mat[(i, 0)];
   224→                if coef.abs() > 1e10 {
   225→                    corrected_coefs.push(0.0);
   226→                } else {
   227→                    corrected_coefs.push(coef);
   228→                }
   229→            }
   230→            Mat::from_fn(n_cols, 1, |i, _| corrected_coefs[i])
   231→        } else {
   232→            coefficients_mat
   233→        };
   234→
   235→        // Calculate fitted values: ŷ = X * β (using corrected coefficients)
   236→        let fitted_mat = &x_mat * &final_coefficients_mat;
   237→
   238→        // Calculate residuals: e = y - ŷ
   239→        let residuals_mat = &y_mat - &fitted_mat;
   240→
   241→        // Extract results to plain Vec<f64> for API
   242→        let coefficients: Vec<f64> = (0..final_coefficients_mat.nrows())
   243→            .map(|i| final_coefficients_mat[(i, 0)])
   244→            .collect();
   245→
   246→        let fitted_values: Vec<f64> = (0..fitted_mat.nrows())
   247→            .map(|i| fitted_mat[(i, 0)])
   248→            .collect();
   249→
   250→        let residuals: Vec<f64> = (0..residuals_mat.nrows())
   251→            .map(|i| residuals_mat[(i, 0)])
   252→            .collect();
   253→
   254→        // rank is already computed above using qr.rank()
   255→
   256→        Ok(LmFit {
   257→            coefficients,
   258→            fitted_values,
   259→            residuals,
   260→            n_obs: n_rows,
   261→            rank,
   262→            x_matrix: x_mat,
   263→        })
   264→    }
   265→}
