   267→impl LmFit {
   268→    /// Get the number of observations used in the model
   269→    pub fn n_obs(&self) -> usize {
   270→        self.n_obs
   271→    }
   272→
   273→    /// Get the rank of the design matrix (number of linearly independent columns)
   274→    pub fn rank(&self) -> usize {
   275→        self.rank
   276→    }
   277→
   278→    /// Get degrees of freedom for error (n_obs - rank)
   279→    pub fn df_resid(&self) -> usize {
   280→        self.n_obs.saturating_sub(self.rank)
   281→    }
   282→}
