   284→impl Glm {
   285→    /// Fit a generalized linear model using ndarray views
   286→    ///
   287→    /// This implementation uses the IRLS algorithm to fit GLMs with any
   288→    /// exponential family distribution and link function.
   289→    ///
   290→    /// # Arguments
   291→    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
   292→    /// * `y` - Response vector as ndarray view (n_observations)
   293→    /// * `family` - Exponential family (Gaussian, Poisson, Binomial)
   294→    /// * `start` - Optional starting values for coefficients
   295→    /// * `config` - Optional IRLS configuration
   296→    pub fn fit_ndarray<F>(
   297→        x: ArrayView2<f64>,
   298→        y: ArrayView1<f64>,
   299→        family: F,
   300→        start: Option<Array1<f64>>,
   301→        config: Option<IrlsConfig>,
   302→    ) -> Result<GlmFit, ModelError>
   303→    where
   304→        F: Family,
   305→    {
   306→        let (n_rows, n_cols) = x.dim();
   307→
   308→        if y.len() != n_rows {
   309→            return Err(ModelError::InvalidModel(
   310→                "Response vector length doesn't match number of observations".to_string(),
   311→            ));
   312→        }
   313→
   314→        let link = family.link();
   315→
   316→        // Define closures for IRLS algorithm
   317→        let link_fn = |mu: f64| link.link(mu);
   318→        let inverse_link_fn = |eta: f64| link.inverse_link(eta);
   319→        let mu_eta_fn = |eta: f64| link.mu_eta(eta);
   320→        let variance_fn = |mu: f64| family.variance(mu);
   321→        let dev_resid_fn = |y: f64, mu: f64| family.dev_resid(y, mu);
   322→
   323→        let functions = optimcore::GlmFunctions {
   324→            link_fn,
   325→            inverse_link_fn,
   326→            mu_eta_fn,
   327→            variance_fn,
   328→            dev_resid_fn,
   329→        };
   330→
   331→        // Run IRLS algorithm
   332→        let irls_result = irls(x, y, functions, start, config)
   333→            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;
   334→
   335→        // Calculate fitted values: μ = g⁻¹(X * β)
   336→        let fitted_values: Vec<f64> = irls_result
   337→            .linear_predictor
   338→            .iter()
   339→            .map(|&eta| inverse_link_fn(eta))
   340→            .collect();
   341→
   342→        // Calculate residuals: e = y - μ
   343→        let residuals: Vec<f64> = y
   344→            .iter()
   345→            .zip(fitted_values.iter())
   346→            .map(|(&y_val, &fitted)| y_val - fitted)
   347→            .collect();
   348→
   349→        // Convert ndarray to faer matrix for storage
   350→        let x_matrix = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);
   351→
   352→        Ok(GlmFit {
   353→            coefficients: irls_result.params.to_vec(),
   354→            fitted_values,
   355→            residuals,
   356→            linear_predictor: irls_result.linear_predictor.to_vec(),
   357→            n_obs: n_rows,
   358→            x_matrix,
   359→            deviance: irls_result.deviance,
   360→            weights: irls_result.weights.to_vec(),
   361→            iterations: irls_result.iterations,
   362→            converged: irls_result.converged,
   363→        })
   364→    }
   365→}
