   513→impl Fit for GlmFit {
   514→    fn coefficients(&self) -> &[f64] {
   515→        &self.coefficients
   516→    }
   517→
   518→    fn fitted(&self) -> &[f64] {
   519→        &self.fitted_values
   520→    }
   521→
   522→    fn residuals(&self) -> &[f64] {
   523→        &self.residuals
   524→    }
   525→
   526→    fn summary(&self) -> ModelSummary {
   527→        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};
   528→
   529→        // For GLM, use deviance-based statistics
   530→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   531→        let n = self.n_obs as f64;
   532→        let p = self.coefficients.len() as f64;
   533→        let df_resid = (n - p).max(0.0);
   534→
   535→        // Use deviance for dispersion estimation in GLM
   536→        let dispersion = if df_resid > 0.0 {
   537→            self.deviance / df_resid
   538→        } else {
   539→            1.0
   540→        };
   541→        let residual_std_error = dispersion.sqrt();
   542→
   543→        // For GLM, R² is calculated differently (based on deviance)
   544→        // Null deviance would be calculated with intercept-only model
   545→        // For now, use a simplified version
   546→        let y_mean: f64 = self
   547→            .fitted_values
   548→            .iter()
   549→            .zip(self.residuals.iter())
   550→            .map(|(fitted, resid)| fitted + resid)
   551→            .sum::<f64>()
   552→            / n;
   553→
   554→        let tss: f64 = self
   555→            .fitted_values
   556→            .iter()
   557→            .zip(self.residuals.iter())
   558→            .map(|(fitted, resid)| {
   559→                let y = fitted + resid;
   560→                (y - y_mean).powi(2)
   561→            })
   562→            .sum();
   563→
   564→        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
   565→        let adj_r_squared = if n > 1.0 && p > 0.0 {
   566→            1.0 - (rss / df_resid) / (tss / (n - 1.0))
   567→        } else {
   568→            r_squared
   569→        };
   570→
   571→        // F-statistic for overall model significance
   572→        let df_model = if p > 1.0 { p as usize - 1 } else { 0 }; // exclude intercept
   573→        let f_statistic = if df_model > 0 {
   574→            model_f_statistic(rss, tss, df_model, df_resid as usize)
   575→        } else {
   576→            0.0
   577→        };
   578→
   579→        let f_p_value = if df_model > 0 && df_resid > 0.0 {
   580→            f_test_p_value(f_statistic, df_model as i32, df_resid as i32)
   581→        } else {
   582→            1.0
   583→        };
   584→
   585→        // Calculate variance-covariance matrix using weights
   586→        // For GLM: Var(β̂) = dispersion * (X'WX)^(-1)
   587→        let n_vars = self.coefficients.len();
   588→        let x_weighted = Mat::from_fn(self.n_obs, n_vars, |i, j| {
   589→            self.weights[i].sqrt() * self.x_matrix[(i, j)]
   590→        });
   591→
   592→        let xtx = x_weighted.transpose() * &x_weighted;
   593→        let qr = xtx.col_piv_qr();
   594→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   595→        let xtx_inv = qr.solve(&identity);
   596→
   597→        // Standard errors for GLM
   598→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   599→            .map(|i| (dispersion * xtx_inv[(i, i)]).sqrt())
   600→            .collect();
   601→
   602→        let t_stats = t_statistics(&self.coefficients, &std_errors);
   603→        let p_values = t_test_p_values(&t_stats, df_resid as i32);
   604→
   605→        let mut coefficient_rows = Vec::new();
   606→        for (i, &coef) in self.coefficients.iter().enumerate() {
   607→            let name = if i == 0 {
   608→                "Intercept".to_string()
   609→            } else {
   610→                format!("X{}", i)
   611→            };
   612→
   613→            coefficient_rows.push(CoefficientRow {
   614→                name,
   615→                estimate: coef,
   616→                std_error: std_errors[i],
   617→                t_value: t_stats[i],
   618→                p_value: p_values[i],
   619→            });
   620→        }
   621→
   622→        ModelSummary {
   623→            coefficients: coefficient_rows,
   624→            r_squared,
   625→            adj_r_squared,
   626→            residual_std_error,
   627→            f_statistic,
   628→            f_p_value,
   629→            df_model,
   630→            df_residual: df_resid as usize,
   631→        }
   632→    }
   633→}
